
'use client'

import { useEffect, useState } from 'react'

type HomeContent = {
  eyebrow: string
  heading: string
  intro: string
  featuredTitle: string
  collectionsTitle: string
  themesTitle: string
}

const defaultHome: HomeContent = {
  eyebrow: 'Decolonising Archive',
  heading: 'The archive of decolonising knowledge',
  intro:
    'Books, oral histories, artefacts, images, textiles, posters, manuscripts, architectural documentation, and cultural records across Africa, the diaspora, and the Global South.',
  featuredTitle: 'Featured Records',
  collectionsTitle: 'Collections',
  themesTitle: 'Browse by Theme',
}

export default function AdminPagesPage() {
  const [page, setPage] = useState('home')
  const [home, setHome] = useState<HomeContent>(defaultHome)
  const [status, setStatus] = useState('')

  useEffect(() => {
    async function loadContent() {
      try {
        const response = await fetch('/api/site-content', { cache: 'no-store' })
        const data = await response.json()
        if (data?.ok && data?.content?.home) {
          setHome(data.content.home)
        }
      } catch (error) {
        console.error('Failed to load page content:', error)
      }
    }

    loadContent()
  }, [])

  function updateField<K extends keyof HomeContent>(field: K, value: HomeContent[K]) {
    setHome((current) => ({ ...current, [field]: value }))
  }

  async function handleSave() {
    setStatus('Saving...')
    try {
      const response = await fetch('/api/site-content', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ home }),
      })

      const data = await response.json()

      if (!response.ok || !data?.ok) {
        throw new Error('Save failed')
      }

      setStatus('Saved')
      window.setTimeout(() => setStatus(''), 2000)
    } catch (error) {
      console.error(error)
      setStatus('Save failed')
    }
  }

  return (
    <div className="admin-editor">
      <div className="admin-header">
        <div>
          <p className="admin-kicker">Pages</p>
          <h1>Edit front-end pages</h1>
          <p className="admin-subtext">
            Update key text, page sections, and editorial content for the public-facing site.
          </p>
        </div>

        <div className="admin-actions">
          <a href="/admin" className="admin-button admin-button-secondary">
            Back to dashboard
          </a>
          <button className="admin-button" type="button" onClick={handleSave}>
            Save changes
          </button>
        </div>
      </div>

      {status ? <p className="admin-save-status">{status}</p> : null}

      <div className="admin-editor-grid">
        <section className="admin-form-panel">
          <div className="admin-form-section">
            <div className="admin-panel-label">Page target</div>
            <label className="admin-field">
              <span>Page</span>
              <select value={page} onChange={(e) => setPage(e.target.value)}>
                <option value="home">Homepage</option>
                <option value="about" disabled>About</option>
                <option value="privacy" disabled>Privacy Policy</option>
                <option value="terms" disabled>Terms of Use</option>
                <option value="copyright" disabled>Copyright &amp; Permissions</option>
                <option value="takedown" disabled>Takedown / Rights Contact</option>
              </select>
            </label>
          </div>

          <div className="admin-form-section">
            <div className="admin-panel-label">Hero content</div>

            <label className="admin-field">
              <span>Eyebrow</span>
              <input
                type="text"
                value={home.eyebrow}
                onChange={(e) => updateField('eyebrow', e.target.value)}
              />
            </label>

            <label className="admin-field">
              <span>Main heading</span>
              <input
                type="text"
                value={home.heading}
                onChange={(e) => updateField('heading', e.target.value)}
              />
            </label>

            <label className="admin-field">
              <span>Intro text</span>
              <textarea
                rows={6}
                value={home.intro}
                onChange={(e) => updateField('intro', e.target.value)}
              />
            </label>
          </div>

          <div className="admin-form-section">
            <div className="admin-panel-label">Section settings</div>

            <label className="admin-field">
              <span>Featured section title</span>
              <input
                type="text"
                value={home.featuredTitle}
                onChange={(e) => updateField('featuredTitle', e.target.value)}
              />
            </label>

            <label className="admin-field">
              <span>Collections section title</span>
              <input
                type="text"
                value={home.collectionsTitle}
                onChange={(e) => updateField('collectionsTitle', e.target.value)}
              />
            </label>

            <label className="admin-field">
              <span>Theme section title</span>
              <input
                type="text"
                value={home.themesTitle}
                onChange={(e) => updateField('themesTitle', e.target.value)}
              />
            </label>
          </div>
        </section>

        <aside className="admin-preview-panel">
          <div className="admin-panel-label">Preview</div>
          <div className="admin-preview-card">
            <p className="admin-preview-eyebrow">{home.eyebrow}</p>
            <h2>{home.heading}</h2>
            <p>{home.intro}</p>
            <div className="admin-preview-meta">
              <span>{home.featuredTitle}</span>
              <span>{home.collectionsTitle}</span>
              <span>{home.themesTitle}</span>
            </div>
          </div>
        </aside>
      </div>
    </div>
  )
}
